const importData = async () => {
    try {
        await Animal.deleteMany(); // Clear existing data
        await Animal.insertMany(animalsData); 
        console.log('Data Imported Successfully!');
        process.exit();
    } catch (error) {
        console.error(`Error: ${error.message}`);
        process.exit(1);
    }
};

importData();